7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This component calculates a binary division of two fixed point values.
11	
12	------------------------------------------------------------------------------
13	-- Libraries
14	------------------------------------------------------------------------------
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.numeric_std.all;
18	
19	library work;
20	use work.psi_common_math_pkg.all;
21	use work.psi_common_logic_pkg.all;
22	use work.psi_common_array_pkg.all;
23	use work.psi_ms_daq_pkg.all;
24	
25	------------------------------------------------------------------------------
26	-- Entity Declaration
27	------------------------------------------------------------------------------
28	-- $$ testcases=single_simple,priorities,single_window,multi_window,enable,irq,timestamp $$
29	-- $$ processes=control,dma_cmd,dma_resp,ctx $$
30	-- $$ tbpkg=work.psi_tb_txt_util,work.psi_tb_compare_pkg $$
31	entity psi_ms_daq_daq_sm is
32	  generic(
33	    Streams_g      : positive range 1 to 32 := 4; -- $$ constant=4 $$		
34	    StreamPrio_g   : t_ainteger             := (1, 2, 3, 1); -- $$ constant=(1, 2, 3, 1) $$
35	    StreamWidth_g  : t_ainteger             := (8, 16, 32, 64); -- $$ constant=(8, 16, 32, 64) $$
36	    Windows_g      : positive range 1 to 32 := 4; -- $$ constant=4 $$
37	    MinBurstSize_g : positive               := 512; -- $$ constant=512 $$
38	    MaxBurstSize_g : positive               := 512 -- $$ constant=512 $$
39	  );
40	  port(
41	    -- Control signals
42	    Clk          : in  std_logic;       -- $$ type=clk; freq=200e6; proc=control,dma_cmd,dma_resp,ctx $$
43	    Rst          : in  std_logic;       -- $$ proc=control $$
44	    GlbEna       : in  std_logic;       -- $$ proc=control; lowactive=true $$
45	    StrEna       : in  std_logic_vector(Streams_g - 1 downto 0); -- $$ proc=control; lowactive=true $$
46	    StrIrq       : out std_logic_vector(Streams_g - 1 downto 0); -- $$ proc=control,dma_resp,dma_cmd; $$
47	    StrLastWin   : out WinType_a(Streams_g - 1 downto 0);
48	    -- Input logic Connections
49	    Inp_HasLast  : in  std_logic_vector(Streams_g - 1 downto 0); -- $$ proc=control $$
50	    Inp_Level    : in  t_aslv16(Streams_g - 1 downto 0); -- $$ proc=control $$
51	    Ts_Vld       : in  std_logic_vector(Streams_g - 1 downto 0); -- $$ proc=control $$
52	    Ts_Rdy       : out std_logic_vector(Streams_g - 1 downto 0); -- $$ proc=control $$
53	    Ts_Data      : in  t_aslv64(Streams_g - 1 downto 0); -- $$ proc=control $$
54	
55	    -- Dma Connections
56	    Dma_Cmd      : out DaqSm2DaqDma_Cmd_t; -- $$ proc=dma_cmd,control $$
57	    Dma_Cmd_Vld  : out std_logic;       -- $$ proc=dma_cmd,control $$
58	    Dma_Resp     : in  DaqDma2DaqSm_Resp_t; -- $$ proc=dma_resp $$
59	    Dma_Resp_Vld : in  std_logic;       -- $$ proc=dma_resp $$
60	    Dma_Resp_Rdy : out std_logic;       -- $$ proc=dma_resp $$
61	
62	    -- Memory Controller
63	    TfDone       : in  std_logic;       -- $$ proc=dma_resp $$
64	
65	    -- Context RAM connections
66	    CtxStr_Cmd   : out ToCtxStr_t;      -- $$ proc=ctx $$
67	    CtxStr_Resp  : in  FromCtx_t;       -- $$ proc=ctx $$
68	    CtxWin_Cmd   : out ToCtxWin_t;      -- $$ proc=ctx $$
69	    CtxWin_Resp  : in  FromCtx_t        -- $$ proc=ctx $$
70	  );
71	end entity;
72	
73	------------------------------------------------------------------------------
74	-- Architecture Declaration
75	------------------------------------------------------------------------------
76	architecture rtl of psi_ms_daq_daq_sm is
77	
78	  -- Number of bits to encode stream is at least 1 (otherwise the special case for one stream would require separate code).
79	  -- .. The overhead generated by this is regarded as aceptable (better wasting a few LUTs than much development time)
80	  constant StreamBits_c : integer := max(log2ceil(Streams_g), 1);
81	
82	  -- Function Definitions
83	  function GetBitsOfStreamPrio(InputVector : std_logic_vector;
84	                               Prio        : integer)
85	  return std_logic_vector is
86	    variable Result_v : std_logic_vector(count(StreamPrio_g, Prio) - 1 downto 0) := (others => '0');
87	    variable OutIdx_v : integer                                                  := 0;
88	  begin
89	    for idx in InputVector'low to InputVector'high loop
90	      if StreamPrio_g(idx) = Prio then
91	        Result_v(OutIdx_v) := InputVector(idx);
92	        OutIdx_v           := OutIdx_v + 1;
93	      end if;
94	    end loop;
95	    return Result_v;
96	  end function;
97	
98	  function GetStreamNrFromGrant(GrantVector : std_logic_vector;
99	                                Prio        : integer)
100	  return integer is
101	    variable IdxCnt_v : integer := 0;
102	  begin
103	    for idx in StreamPrio_g'low to StreamPrio_g'high loop
104	      if StreamPrio_g(idx) = Prio then
105	        if GrantVector(IdxCnt_v) = '1' then
106	          return idx;
107	        end if;
108	        IdxCnt_v := IdxCnt_v + 1;
109	      end if;
110	    end loop;
111	    return 0;
112	  end function;
113	
114	  -- Vivado Workarounds (Synthesis fail)
115	  subtype Log2Bytes_t is integer range 0 to log2(MaxStreamWidth_c / 8);
116	  type Log2Bytes_a is array (natural range <>) of Log2Bytes_t;
117	  function CalcLog2Bytes return Log2Bytes_a is
118	    variable arr : Log2Bytes_a(0 to Streams_g - 1);
119	  begin
120	    for i in 0 to Streams_g - 1 loop
121	      arr(i) := log2(StreamWidth_g(i) / 8);
122	    end loop;
123	    return arr;
124	  end function;
125	  constant Log2StrBytes_c : Log2Bytes_a(0 to Streams_g - 1) := CalcLog2Bytes;
126	
127	  -- Component Connection Signals
128	  signal AvailPrio1     : std_logic_vector(count(StreamPrio_g, 1) - 1 downto 0);
129	  signal AvailPrio2     : std_logic_vector(count(StreamPrio_g, 2) - 1 downto 0);
130	  signal AvailPrio3     : std_logic_vector(count(StreamPrio_g, 3) - 1 downto 0);
131	  signal GrantPrio1     : std_logic_vector(AvailPrio1'range);
132	  signal GrantPrio2     : std_logic_vector(AvailPrio2'range);
133	  signal GrantPrio3     : std_logic_vector(AvailPrio3'range);
134	  signal GrantVld       : std_logic_vector(3 downto 1);
135	  signal IrqFifoAlmFull : std_logic;
136	  signal IrqFifoEmpty   : std_logic;
137	  signal IrqFifoGenIrq  : std_logic;
138	  signal IrqFifoStream  : std_logic_vector(StreamBits_c - 1 downto 0);
139	  signal IrqLastWinNr   : std_logic_vector(log2ceil(Windows_g) - 1 downto 0);
140	  signal IrqFifoIn      : std_logic_vector(StreamBits_c + log2ceil(Windows_g) downto 0);
141	  signal IrqFifoOut     : std_logic_vector(StreamBits_c + log2ceil(Windows_g) downto 0);
142	
143	  -- Types
144	  type State_t is (Idle_s, CheckPrio1_s, CheckPrio2_s, CheckPrio3_s, CheckResp_s, TlastCheck_s, ReadCtxStr_s, First_s, ReadCtxWin_s, CalcAccess0_s, CalcAccess1_s, ProcResp0_s, NextWin_s, WriteCtx_s);
145	
146	  -- Two process method
147	  type two_process_r is record
148	    GlbEnaReg      : std_logic;
149	    StrEnaReg      : std_logic_vector(Streams_g - 1 downto 0);
150	    InpDataAvail   : std_logic_vector(Streams_g - 1 downto 0);
151	    DataAvailArbIn : std_logic_vector(Streams_g - 1 downto 0);
152	    DataPending    : std_logic_vector(Streams_g - 1 downto 0);
153	    OpenCommand    : std_logic_vector(Streams_g - 1 downto 0);
154	    WinProtected   : std_logic_vector(Streams_g - 1 downto 0); -- Set if the current window is not yet available
155	    NewBuffer      : std_logic_vector(Streams_g - 1 downto 0);
156	    FirstAfterEna  : std_logic_vector(Streams_g - 1 downto 0);
157	    FirstOngoing   : std_logic_vector(Streams_g - 1 downto 0);
158	    GrantVldReg    : std_logic_vector(3 downto 1);
159	    State          : State_t;
160	    GrantPrio1Reg  : std_logic_vector(GrantPrio1'range);
161	    GrantPrio2Reg  : std_logic_vector(GrantPrio2'range);
162	    GrantPrio3Reg  : std_logic_vector(GrantPrio3'range);
163	    HasLastReg     : std_logic_vector(Inp_HasLast'range);
164	    HndlAfterCtxt  : State_t;
165	    HndlStream     : integer range 0 to Streams_g;
166	    HndlCtxCnt     : integer range 0 to 4;
167	    HndlRingbuf    : std_logic;
168	    HndlOverwrite  : std_logic;
169	    HndlWincnt     : std_logic_vector(log2ceil(Windows_g) - 1 downto 0);
170	    HndlWincur     : std_logic_vector(log2ceil(Windows_g) - 1 downto 0);
171	    HndlLastWinNr  : std_logic_vector(log2ceil(Windows_g) - 1 downto 0);
172	    HndlBufstart   : std_logic_vector(31 downto 0);
173	    HndlWinSize    : std_logic_vector(31 downto 0);
174	    HndlPtr0       : std_logic_vector(31 downto 0);
175	    HndlPtr1       : std_logic_vector(31 downto 0);
176	    HndlPtr2       : std_logic_vector(31 downto 0);
177	    HndlLevel      : std_logic_vector(15 downto 0);
178	    Hndl4kMax      : std_logic_vector(12 downto 0);
179	    HndlWinMax     : std_logic_vector(31 downto 0);
180	    HndlWinEnd     : std_logic_vector(31 downto 0);
181	    HndlWinBytes   : std_logic_vector(32 downto 0);
182	    HndlWinLast    : std_logic_vector(31 downto 0);
183	    HndlTs         : std_logic_vector(63 downto 0);
184	    TfDoneCnt      : std_logic_vector(StreamBits_c - 1 downto 0);
185	    TfDoneReg      : std_logic;
186	    HndlWinDone    : std_logic;
187	    CtxStr_Cmd     : ToCtxStr_t;
188	    CtxWin_Cmd     : ToCtxWin_t;
189	    Dma_Cmd        : DaqSm2DaqDma_Cmd_t;
190	    Dma_Cmd_Vld    : std_logic;
191	    Dma_Resp_Rdy   : std_logic;
192	    Ts_Rdy         : std_logic_vector(Streams_g - 1 downto 0);
193	    ArbDelCnt      : integer range 0 to 4;
194	    IrqFifoWrite   : std_logic;
195	    IrqFifoRead    : std_logic;
196	    StrIrq         : std_logic_vector(Streams_g - 1 downto 0);
197	    StrLastWin     : WinType_a(Streams_g - 1 downto 0);
198	    EndByTrig      : std_logic;
199	  end record;
200	  signal r, r_next : two_process_r;
201	
202	  -- USED FOR DEBUGGING ONLY!
203	  -- attribute mark_debug : string;
204	  -- attribute mark_debug of r : signal is "true";
205	
206	  -- Todo: mask streams that already have a transfer open at the input
207	
208	begin
209	  --------------------------------------------
210	  -- Combinatorial Process
211	  --------------------------------------------
212	  p_comb : process(r, Inp_HasLast, Inp_Level, Ts_Vld, Ts_Data, Dma_Resp, Dma_Resp_Vld, CtxStr_Resp, CtxWin_Resp, GlbEna, StrEna, TfDone, IrqFifoGenIrq, IrqFifoStream, IrqLastWinNr, GrantVld, GrantPrio1, GrantPrio2, GrantPrio3, IrqFifoAlmFull, IrqFifoEmpty)
213	    variable v : two_process_r;
214	  begin
215	    -- *** Hold variables stable ***
216	    v := r;
217	
218	    -- *** Default Values ***
219	    v.CtxStr_Cmd.WenLo  := '0';
220	    v.CtxStr_Cmd.WenHi  := '0';
221	    v.CtxWin_Cmd.WenLo  := '0';
222	    v.CtxWin_Cmd.WenHi  := '0';
223	    v.CtxStr_Cmd.Rd     := '0';
224	    v.CtxWin_Cmd.Rd     := '0';
225	    v.Dma_Cmd_Vld       := '0';
226	    v.Ts_Rdy            := (others => '0');
227	    v.Dma_Resp_Rdy      := '0';
228	    v.CtxWin_Cmd.WdatLo := (others => '0');
229	    v.CtxWin_Cmd.WdatHi := (others => '0');
230	    v.CtxStr_Cmd.WdatLo := (others => '0');
231	    v.CtxStr_Cmd.WdatHi := (others => '0');
232	    v.IrqFifoWrite      := '0';
233	    v.IrqFifoRead       := '0';
234	    v.StrIrq            := (others => '0');
235	
236	    -- *** Pure Pipelining (no functional registers) ***
237	    v.GrantVldReg   := GrantVld;
238	    v.GrantPrio1Reg := GrantPrio1;
239	    v.GrantPrio2Reg := GrantPrio2;
240	    v.GrantPrio3Reg := GrantPrio3;
241	    v.HasLastReg    := Inp_HasLast;
242	    v.StrEnaReg     := StrEna;
243	    v.GlbEnaReg     := GlbEna;
244	    v.TfDoneReg     := TfDone;
245	
246	    -- *** Check Availability of a full burst ***
247	    for str in 0 to Streams_g - 1 loop
248	      if unsigned(Inp_Level(str)) >= MinBurstSize_g then
249	        v.InpDataAvail(str) := r.StrEnaReg(str) and r.GlbEnaReg;
250	      else
251	        v.InpDataAvail(str) := '0';
252	      end if;
253	    end loop;
254	    v.DataAvailArbIn := r.InpDataAvail and (not r.OpenCommand) and (not r.WinProtected); -- Do not arbitrate new commands on streams that already have a command
255	    v.DataPending    := r.InpDataAvail and (not r.WinProtected); -- Do not prevent lower priority channels from access if the window of a higher priority stream is protected
256	
257	    -- *** Select level of currently handled FIFO ***
258	    v.HndlLevel := Inp_Level(r.HndlStream);
259	
260	    -- *** State Machine ***
261	    case r.State is
262	      -- *** Idle state ***
263	      when Idle_s =>
264	        v.HndlCtxCnt  := 0;
265	        v.HndlWinDone := '0';
266	        -- check if data to write is available	(only if IRQ FIFO has space for the response for sure)
267	        if IrqFifoAlmFull = '0' then
268	          v.State         := CheckPrio1_s;
269	          v.HndlAfterCtxt := CalcAccess0_s;
270	        end if;
271	        -- Delay arbitration in simulation to allow TB to react
272	        if r.ArbDelCnt /= 4 then
273	          v.State     := Idle_s;
274	          v.ArbDelCnt := r.ArbDelCnt + 1;
275	        else
276	          v.ArbDelCnt := 0;
277	        end if;
278	
279	      -- *** Check for next stream to handle ***
280	      when CheckPrio1_s =>
281	        -- Handle command if prio 1 data is available
282	        if r.GrantVldReg(1) = '1' then
283	          v.State      := ReadCtxStr_s;
284	          v.HndlStream := GetStreamNrFromGrant(r.GrantPrio1Reg, 1);
285	        -- If data is still pending, check for responses to schedule next transfer
286	        elsif (unsigned(GetBitsOfStreamPrio(r.DataPending, 1)) /= 0) and (count(StreamPrio_g, 1) /= 0) then -- the term after the AND is required because unsigned(null-range) is not guaranteed to be zero in Vivado
287	          v.State := CheckResp_s;
288	        -- Otherwise check lower priority streams
289	        else
290	          v.State := CheckPrio2_s;
291	        end if;
292	
293	      when CheckPrio2_s =>
294	        -- Handle command if prio 2 data is available
295	        if r.GrantVldReg(2) = '1' then
296	          v.State      := ReadCtxStr_s;
297	          v.HndlStream := GetStreamNrFromGrant(r.GrantPrio2Reg, 2);
298	        -- If data is still pending, check for responses to schedule next transfer
299	        elsif (unsigned(GetBitsOfStreamPrio(r.DataPending, 2)) /= 0) and (count(StreamPrio_g, 2) /= 0) then -- the term after the AND is required because unsigned(null-range) is not guaranteed to be zero in Vivado
300	          v.State := CheckResp_s;
301	        -- Otherwise check lower priority streams
302	        else
303	          v.State := CheckPrio3_s;
304	        end if;
305	
306	      when CheckPrio3_s =>
307	        -- Handle command if prio 2 data is available
308	        if r.GrantVldReg(3) = '1' then
309	          v.State      := ReadCtxStr_s;
310	          v.HndlStream := GetStreamNrFromGrant(r.GrantPrio3Reg, 3);
311	        -- Otherwise check for frame ends
312	        else
313	          v.State := TlastCheck_s;
314	        end if;
315	
316	      when TlastCheck_s =>
317	        v.State        := CheckResp_s;
318	        v.WinProtected := (others => '0'); -- No bursts where available on any stream, so all of them were checked and we can retry whether SW emptied a window.
319	        for idx in 0 to Streams_g - 1 loop
320	          if (r.HasLastReg(idx) = '1') and (r.OpenCommand(idx) = '0') and (r.WinProtected(idx) = '0') then
321	            v.State      := ReadCtxStr_s;
322	            v.HndlStream := idx;
323	          end if;
324	        end loop;
325	
326	      when CheckResp_s =>
327	        -- Handle response if one is pending (less important thandata transer, therefore at the end)
328	        if Dma_Resp_Vld = '1' then
329	          v.State         := ReadCtxStr_s;
330	          v.HndlAfterCtxt := ProcResp0_s;
331	          v.HndlStream    := Dma_Resp.Stream;
332	          v.EndByTrig     := Dma_Resp.Trigger;
333	        else
334	          v.State := Idle_s;
335	        end if;
336	
337	      -- *** Read Context Memory ***
338	      -- Read information from stream memory
339	      when ReadCtxStr_s =>
340	        -- State handling
341	        if r.HndlCtxCnt = 4 then
342	          v.State      := First_s;
343	          v.HndlCtxCnt := 0;
344	        else
345	          v.HndlCtxCnt := r.HndlCtxCnt + 1;
346	        end if;
347	
348	        -- Command Assertions
349	        v.CtxStr_Cmd.Stream := r.HndlStream;
350	        case r.HndlCtxCnt is
351	          when 0 => v.CtxStr_Cmd.Sel := CtxStr_Sel_Winend_c;
352	            v.CtxStr_Cmd.Rd  := '1';
353	          when 1 => v.CtxStr_Cmd.Sel := CtxStr_Sel_WinsizePtr_c;
354	            v.CtxStr_Cmd.Rd  := '1';
355	          when 2 => v.CtxStr_Cmd.Sel := CtxStr_Sel_ScfgBufstart_c;
356	            v.CtxStr_Cmd.Rd  := '1';
357	          when others => null;
358	        end case;
359	
360	        -- Response handling
361	        case r.HndlCtxCnt is
362	          when 2 => v.HndlWinEnd := CtxStr_Resp.RdatLo;
363	          when 3 => v.HndlWinSize := CtxStr_Resp.RdatLo;
364	            v.HndlPtr0    := CtxStr_Resp.RdatHi;
365	          when 4 => v.HndlRingbuf   := CtxStr_Resp.RdatLo(CtxStr_Sft_SCFG_RINGBUF_c);
366	            v.HndlOverwrite := CtxStr_Resp.RdatLo(CtxStr_Sft_SCFG_OVERWRITE_c);
367	            v.HndlWincnt    := CtxStr_Resp.RdatLo(CtxStr_Sft_SCFG_WINCNT_c + v.HndlWincnt'high downto CtxStr_Sft_SCFG_WINCNT_c);
368	            v.HndlWincur    := CtxStr_Resp.RdatLo(CtxStr_Sft_SCFG_WINCUR_c + v.HndlWincur'high downto CtxStr_Sft_SCFG_WINCUR_c);
369	            v.HndlBufstart  := CtxStr_Resp.RdatHi;
370	            v.Hndl4kMax     := std_logic_vector(to_unsigned(4096, 13) - unsigned(r.HndlPtr0(11 downto 0))); -- Calculate maximum size within this 4k Region
371	            v.HndlWinMax    := std_logic_vector(unsigned(r.HndlWinEnd) - unsigned(r.HndlPtr0)); -- Calculate maximum size within this window
372	          when others => null;
373	        end case;
374	
375	      -- Handle first access after enable
376	      when First_s =>
377	        -- State handling
378	        v.State := ReadCtxWin_s;
379	
380	        -- Ensure that command and response are both handled as first or not
381	        if r.HndlAfterCtxt = ProcResp0_s then -- responses
382	          -- nothing to do
383	        else                            -- command
384	          v.FirstAfterEna(r.HndlStream) := '0';
385	          v.FirstOngoing(r.HndlStream)  := r.FirstAfterEna(r.HndlStream);
386	        end if;
387	
388	        -- Update values for first access
389	        if v.FirstOngoing(r.HndlStream) = '1' then
390	          v.HndlWinEnd := std_logic_vector(unsigned(r.HndlBufstart) + unsigned(r.HndlWinSize));
391	          v.HndlPtr0   := r.HndlBufstart;
392	          v.HndlWincur := (others => '0');
393	          v.Hndl4kMax  := std_logic_vector(to_unsigned(4096, 13) - unsigned(r.HndlBufstart(11 downto 0)));
394	          v.HndlWinMax := r.HndlWinSize;
395	        end if;
396	
397	      -- Read information from window memory
398	      when ReadCtxWin_s =>
399	        -- State handling
400	        if r.HndlCtxCnt = 2 then
401	          v.State := r.HndlAfterCtxt;   -- Goto state depends on the context of the read procedure
402	        else
403	          v.HndlCtxCnt := r.HndlCtxCnt + 1;
404	        end if;
405	
406	        -- Command Assertions
407	        v.CtxWin_Cmd.Stream := r.HndlStream;
408	        v.CtxWin_Cmd.Window := to_integer(unsigned(r.HndlWincur));
409	        case r.HndlCtxCnt is
410	          when 0 => v.CtxWin_Cmd.Sel := CtxWin_Sel_WincntWinlast_c;
411	            v.CtxWin_Cmd.Rd  := '1';
412	          when others => null;
413	        end case;
414	
415	        -- Response handling
416	        case r.HndlCtxCnt is
417	          when 2 =>
418	            -- Workaround for Vivado (Range expression was resolved incorrectly)
419	            for i in 0 to Streams_g - 1 loop
420	              if i = r.HndlStream then
421	                v.HndlWinBytes := '0' & shift_left(CtxWin_Resp.RdatLo, Log2StrBytes_c(i)); -- guard bit required for calculations
422	              end if;
423	            end loop;
424	          when others => null;
425	        end case;
426	
427	      -- *** Calculate next access ***
428	      when CalcAccess0_s =>
429	        -- Calculate Command
430	        v.Dma_Cmd.Address := r.HndlPtr0;
431	        v.Dma_Cmd.Stream  := r.HndlStream;
432	        v.Dma_Cmd.MaxSize := std_logic_vector(to_unsigned(MaxBurstSize_g * 8, v.Dma_Cmd.MaxSize'length)); -- 8 bytes per 64-bit QWORD
433	        -- State update (abort if window is not free)
434	        if (r.HndlOverwrite = '0') and (unsigned(r.HndlWinBytes) /= 0) and (r.NewBuffer(r.HndlStream) = '1') then
435	          v.State                      := Idle_s;
436	          v.WinProtected(r.HndlStream) := '1';
437	        else
438	          v.State                     := CalcAccess1_s;
439	          v.NewBuffer(r.HndlStream)   := '0';
440	          -- Mark stream as active
441	          v.OpenCommand(r.HndlStream) := '1';
442	        end if;
443	
444	      when CalcAccess1_s =>
445	        if unsigned(r.Hndl4kMax) < unsigned(r.HndlWinMax) then
446	          if unsigned(r.Dma_Cmd.MaxSize) > unsigned(r.Hndl4kMax) then
447	            v.Dma_Cmd.MaxSize := std_logic_vector(resize(unsigned(r.Hndl4kMax), v.dma_Cmd.MaxSize'length));
448	          end if;
449	        else
450	          if unsigned(r.Dma_Cmd.MaxSize) > unsigned(r.HndlWinMax) then
451	            v.Dma_Cmd.MaxSize := std_logic_vector(resize(unsigned(r.HndlWinMax), v.dma_Cmd.MaxSize'length));
452	          end if;
453	        end if;
454	        v.Dma_Cmd_Vld := '1';
455	        v.State       := Idle_s;
456	
457	      -- *** Handle response ***		
458	      -- Calculate next pointer
459	      when ProcResp0_s =>
460	        v.OpenCommand(r.HndlStream)  := '0';
461	        v.FirstOngoing(r.HndlStream) := '0';
462	        v.HndlPtr1                   := std_logic_vector(unsigned(r.HndlPtr0) + unsigned(Dma_Resp.Size));
463	        v.State                      := NextWin_s;
464	        -- Update window information step 1
465	        v.HndlWinBytes               := std_logic_vector(unsigned(r.HndlWinBytes) + unsigned(Dma_Resp.Size));
466	
467	      -- Calculate next window to use
468	      when NextWin_s =>
469	        -- Default Values
470	        v.HndlPtr2      := r.HndlPtr1;
471	        -- Do not wait for "transfer done" for zero size transfers (they are not passed to the memory interface)
472	        if unsigned(Dma_Resp.Size) /= 0 then
473	          v.IrqFifoWrite := '1';
474	        end if;
475	        -- Switch to next window if required	
476	        v.HndlLastWinNr := r.HndlWincur;
477	        if ((r.HndlPtr1 = r.HndlWinEnd) and (r.HndlRingbuf = '0')) or (Dma_Resp.Trigger = '1') then
478	          v.HndlWinDone             := '1';
479	          v.NewBuffer(r.HndlStream) := '1';
480	          if r.HndlWincur = r.HndlWincnt then
481	            v.HndlWincur := (others => '0');
482	            v.HndlPtr2   := r.HndlBufstart;
483	            v.HndlWinEnd := std_logic_vector(unsigned(r.HndlBufstart) + unsigned(r.HndlWinSize));
484	          else
485	            v.HndlWincur := std_logic_vector(unsigned(r.HndlWincur) + 1);
486	            v.HndlPtr2   := r.HndlWinEnd;
487	            v.HndlWinEnd := std_logic_vector(unsigned(r.HndlWinEnd) + unsigned(r.HndlWinSize));
488	          end if;
489	        end if;
490	        -- wraparound for ringbuffer case
491	        if (r.HndlPtr1 = r.HndlWinEnd) and (r.HndlRingbuf = '1') and (Dma_Resp.Trigger = '0') then
492	          v.HndlPtr2 := std_logic_vector(unsigned(r.HndlPtr1) - unsigned(r.HndlWinSize));
493	        end if;
494	        -- Update window information step 2 (limit to maximum value)
495	        if unsigned(r.HndlWinBytes) > unsigned(r.HndlWinSize) then
496	          v.HndlWinBytes := '0' & r.HndlWinSize; -- value has a guard bit
497	        end if;
498	        -- Store address of last sample in window
499	        v.HndlWinLast   := std_logic_vector(unsigned(r.HndlPtr1) - StreamWidth_g(r.HndlStream) / 8);
500	        -- Latch timestamp
501	        if (Dma_Resp.Trigger = '1') and (Ts_Vld(r.HndlStream) = '1') then
502	          v.Ts_Rdy(r.HndlStream) := '1';
503	          v.HndlTs               := Ts_Data(r.HndlStream);
504	        else
505	          v.HndlTs := (others => '1');
506	        end if;
507	        -- Write values
508	        v.State         := WriteCtx_s;
509	        v.HndlCtxCnt    := 0;
510	        -- Response is processed
511	        v.Dma_Resp_Rdy  := '1';
512	
513	      -- Write Context Memory Content
514	      when WriteCtx_s =>
515	        -- Update State
516	        if r.HndlCtxCnt = 2 then
517	          v.State := Idle_s;
518	        else
519	          v.HndlCtxCnt := r.HndlCtxCnt + 1;
520	        end if;
521	        -- Write Context Memory
522	        v.CtxStr_Cmd.Stream := v.HndlStream;
523	        case r.HndlCtxCnt is
524	          when 0 =>
525	            -- Stream Memory
526	            v.CtxStr_Cmd.Sel                                                                                  := CtxStr_Sel_ScfgBufstart_c;
527	            v.CtxStr_Cmd.WenLo                                                                                := '1';
528	            v.CtxStr_Cmd.WdatLo(CtxStr_Sft_SCFG_RINGBUF_c)                                                    := r.HndlRingbuf;
529	            v.CtxStr_Cmd.WdatLo(CtxStr_Sft_SCFG_OVERWRITE_c)                                                  := r.HndlOverwrite;
530	            v.CtxStr_Cmd.WdatLo(CtxStr_Sft_SCFG_WINCNT_c + v.HndlWincnt'high downto CtxStr_Sft_SCFG_WINCNT_c) := r.HndlWincnt;
531	            v.CtxStr_Cmd.WdatLo(CtxStr_Sft_SCFG_WINCUR_c + v.HndlWincur'high downto CtxStr_Sft_SCFG_WINCUR_c) := r.HndlWincur;
532	            -- Window Memory
533	            v.CtxWin_Cmd.Sel                                                                                  := CtxWin_Sel_WincntWinlast_c;
534	            v.CtxWin_Cmd.WenLo                                                                                := '1';
535	            v.CtxWin_Cmd.WenHi                                                                                := '1';
536	            v.CtxWin_Cmd.WdatLo                                                                               := shift_right(r.HndlWinBytes(31 downto 0), Log2StrBytes_c(r.HndlStream)); -- cut-off guard bit and convert bytes to samples
537	            v.CtxWin_Cmd.WdatLo(31)                                                                           := r.EndByTrig;
538	            v.CtxWin_Cmd.WdatHi                                                                               := r.HndlWinLast;
539	          when 1 =>
540	            -- Stream Memory
541	            v.CtxStr_Cmd.Sel    := CtxStr_Sel_WinsizePtr_c;
542	            v.CtxStr_Cmd.WenHi  := '1';
543	            v.CtxStr_Cmd.WdatHi := r.HndlPtr2;
544	            -- Window Memory
545	            if r.HndlWinDone = '1' then
546	              v.CtxWin_Cmd.Sel    := CtxWin_Sel_WinTs_c;
547	              v.CtxWin_Cmd.WenHi  := '1';
548	              v.CtxWin_Cmd.WenLo  := '1';
549	              v.CtxWin_Cmd.WdatLo := r.HndlTs(31 downto 0);
550	              v.CtxWin_Cmd.WdatHi := r.HndlTs(63 downto 32);
551	            end if;
552	          when 2 =>
553	            -- Stream Memory
554	            v.CtxStr_Cmd.Sel    := CtxStr_Sel_Winend_c;
555	            v.CtxStr_Cmd.WenLo  := '1';
556	            v.CtxStr_Cmd.WdatLo := r.HndlWinEnd;
557	          when others => null;
558	        end case;
559	    end case;
560	
561	    -- *** Handle Disabled Streams ***
562	    for str in 0 to Streams_g - 1 loop
563	      if (r.GlbEnaReg = '0') or (r.StrEnaReg(str) = '0') then
564	        v.FirstAfterEna(str) := '1';
565	        v.NewBuffer(str)     := '1';
566	      end if;
567	    end loop;
568	
569	    -- *** IRQ Handling ***
570	    -- Feedback from memory controller
571	    if r.TfDoneReg = '1' then
572	      v.TfDoneCnt := std_logic_vector(unsigned(r.TfDoneCnt) + 1);
573	    end if;
574	
575	    -- Process transfer completion
576	    if (unsigned(r.TfDoneCnt) /= 0) and (IrqFifoEmpty = '0') then
577	      v.IrqFifoRead := '1';
578	      v.TfDoneCnt   := std_logic_vector(unsigned(v.TfDoneCnt) - 1);
579	    end if;
580	
581	    -- Generate IRQ if required
582	    if IrqFifoGenIrq = '1' and r.IrqFifoRead = '1' then
583	      v.StrIrq(to_integer(unsigned(IrqFifoStream)))     := '1';
584	      v.StrLastWin(to_integer(unsigned(IrqFifoStream))) := std_logic_vector(resize(unsigned(IrqLastWinNr), 5));
585	    end if;
586	
587	    -- *** Assign to signal ***
588	    r_next <= v;
589	
590	  end process;
591	
592	  -- *** Registered Outputs ***
593	  CtxStr_Cmd   <= r.CtxStr_Cmd;
594	  CtxWin_Cmd   <= r.CtxWin_Cmd;
595	  Dma_Cmd_Vld  <= r.Dma_Cmd_Vld;
596	  Dma_Cmd      <= r.Dma_Cmd;
597	  Dma_Resp_Rdy <= r.Dma_Resp_Rdy;
598	  Ts_Rdy       <= r.Ts_Rdy;
599	  StrIrq       <= r.StrIrq;
600	  StrLastWin   <= r.StrLastWin;
601	
602	  --------------------------------------------
603	  -- Sequential Process
604	  --------------------------------------------
605	  p_seq : process(Clk)
606	  begin
607	    if rising_edge(Clk) then
608	      r <= r_next;
609	      if Rst = '1' then
610	        r.ArbDelCnt        <= 0;
611	        r.InpDataAvail     <= (others => '0');
612	        r.DataAvailArbIn   <= (others => '0');
613	        r.HndlStream       <= 0;
614	        r.State            <= Idle_s;
615	        r.CtxStr_Cmd.WenLo <= '0';
616	        r.CtxStr_Cmd.WenHi <= '0';
617	        r.CtxWin_Cmd.WenLo <= '0';
618	        r.CtxWin_Cmd.WenHi <= '0';
619	        r.Dma_Cmd_Vld      <= '0';
620	        r.OpenCommand      <= (others => '0');
621	        r.WinProtected     <= (others => '0');
622	        r.Dma_Resp_Rdy     <= '0';
623	        r.Ts_Rdy           <= (others => '0');
624	        r.GlbEnaReg        <= '0';
625	        r.FirstOngoing     <= (others => '0');
626	        r.TfDoneCnt        <= (others => '0');
627	        r.TfDoneReg        <= '0';
628	        r.IrqFifoWrite     <= '0';
629	        r.IrqFifoRead      <= '0';
630	        r.StrIrq           <= (others => '0');
631	        r.StrLastWin       <= (others => (others => '0'));
632	      end if;
633	    end if;
634	  end process;
635	
636	  --------------------------------------------
637	  -- Component Instantiation
638	  --------------------------------------------
639	  -- *** Round Robin Arbiter - Prio 1 ***
640	  AvailPrio1  <= GetBitsOfStreamPrio(r.DataAvailArbIn, 1);
641	  i_rrarb_1 : entity work.psi_common_arb_priority
642	    generic map(
643	      width_g => count(StreamPrio_g, 1)
644	    )
645	    port map(
646	      clk_i   => Clk,
647	      rst_i   => Rst,
648	      req_i   => AvailPrio1,
649	      grant_o => GrantPrio1
650	    );
651	  GrantVld(1) <= '1' when (unsigned(GrantPrio1) /= 0) and (GrantPrio1'length > 0) else '0';
652	
653	  -- *** Round Robin Arbiter - Prio 2 ***
654	  AvailPrio2  <= GetBitsOfStreamPrio(r.DataAvailArbIn, 2);
655	  i_rrarb_2 : entity work.psi_common_arb_priority
656	    generic map(
657	      width_g => count(StreamPrio_g, 2)
658	    )
659	    port map(
660	      clk_i   => Clk,
661	      rst_i   => Rst,
662	      req_i   => AvailPrio2,
663	      grant_o => GrantPrio2
664	    );
665	  GrantVld(2) <= '1' when (unsigned(GrantPrio2) /= 0) and (GrantPrio2'length > 0) else '0';
666	
667	  -- *** Round Robin Arbiter - Prio 3 ***
668	  AvailPrio3  <= GetBitsOfStreamPrio(r.DataAvailArbIn, 3);
669	  i_rrarb_3 : entity work.psi_common_arb_priority
670	    generic map(
671	      width_g => count(StreamPrio_g, 3)
672	    )
673	    port map(
674	      clk_i   => Clk,
675	      rst_i   => Rst,
676	      req_i   => AvailPrio3,
677	      grant_o => GrantPrio3
678	    );
679	  GrantVld(3) <= '1' when (unsigned(GrantPrio3) /= 0) and (GrantPrio3'length > 0) else '0';
680	
681	  -- *** IRQ Information FIFO ***
682	  -- input assembly
683	  IrqFifoIn(StreamBits_c - 1 downto 0)                                  <= std_logic_vector(to_unsigned(r.HndlStream, StreamBits_c));
684	  IrqFifoIn(StreamBits_c + log2ceil(Windows_g) - 1 downto StreamBits_c) <= r.HndlLastWinNr;
685	  IrqFifoIn(IrqFifoIn'high)                                             <= r.HndlWinDone;
686	
687	  -- Instantiation
688	  i_irq_fifo : entity work.psi_common_sync_fifo
689	    generic map(
690	      width_g          => StreamBits_c + log2ceil(Windows_g) + 1,
691	      depth_g          => 2**StreamBits_c * 4,
692	      alm_full_on_g    => true,
693	      alm_full_level_g => Streams_g * 3,
694	      ram_style_g      => "distributed"
695	    )
696	    port map(
697	      clk_i      => Clk,
698	      rst_i      => Rst,
699	      dat_i      => IrqFifoIn,
700	      vld_i      => r.IrqFifoWrite,
701	      dat_o      => IrqFifoOut,
702	      rdy_i      => r.IrqFifoRead,
703	      alm_full_o => IrqFifoAlmFull,
704	      empty_o    => IrqFifoEmpty
705	    );
706	
707	  -- Output disassembly
708	  IrqFifoStream <= IrqFifoOut(StreamBits_c - 1 downto 0);
709	  IrqLastWinNr  <= IrqFifoOut(StreamBits_c + log2ceil(Windows_g) - 1 downto StreamBits_c);
710	  IrqFifoGenIrq <= IrqFifoOut(IrqFifoOut'high);
711	
712	end;
713	
714

