93		begin
94			print(">> -- irq --");	
95			
96			-- Normal Order
97			print(">> Normal Order");
98			InitTestCase(Clk, Rst);
99			TestCase := 0;
100			ConfigureAuto(	WinSize => 4096, Ringbuf => '0', Overwrite => '1', Wincnt => 2, Wincur => 0);	
101			Inp_Level(0) <= LvlThreshold_c;		
102			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
103			Inp_Level(0) <= (others => '0');
104			ControlWaitCompl(Clk);			
105			
106			-- Flipped Order
107			print(">> Flipped Order");
108			InitTestCase(Clk, Rst);
109			TestCase := 1;
110			ConfigureAuto(	WinSize => 4096, Ringbuf => '0', Overwrite => '1', Wincnt => 2, Wincur => 0);	
111			Inp_Level(0) <= LvlThreshold_c;		
112			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
113			Inp_Level(0) <= (others => '0');
114			ControlWaitCompl(Clk);			
115			
116			-- IRQ FIFO full
117			-- ... FIFO is full after Streams (4) x 3 = 12 open transfers
118			print(">> IRQ FIFO full");
119			InitTestCase(Clk, Rst);
120			TestCase := 2;
121			ConfigureAuto(	WinSize => 4096, Ringbuf => '0', Overwrite => '1', Wincnt => 2, Wincur => 0);	
122			Inp_Level(0) <= LvlThreshold_c;	
123			-- Fill FIFO
124			for i in 0 to 11 loop
125				wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
126			end loop;
127			-- Checked transfer
128			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
129			Inp_Level(0) <= (others => '0');
130			ControlWaitCompl(Clk);		
131	
132			-- Multi-Stream
133			wait for 1 us;
134			print(">> Multi-Stream");
135			InitTestCase(Clk, Rst);
136			TestCase := 3;
137			ConfigureAuto(	WinSize => 4096, Ringbuf => '0', Overwrite => '1', Wincnt => 2, Wincur => 0);	
138			for i in 3 downto 0 loop
139				Inp_Level(i) <= LvlThreshold_c;	
140				wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';			
141				Inp_Level(i) <= (others => '0');
142				wait for 200 ns;
143			end loop;
144			ControlWaitCompl(Clk);			
145			
146			-- Win-Change without trigger
147			wait for 1 us;
148			print(">> Win-Change without trigger");
149			InitTestCase(Clk, Rst);
150			TestCase := 4;
151			ConfigureAuto(	WinSize => 4096*2, Ringbuf => '0', Overwrite => '1', Wincnt => 2, Wincur => 0);	
152			Inp_Level(0) <= LvlThreshold_c;		
153			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
154			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
155			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
156			Inp_Level(0) <= (others => '0');
157			ControlWaitCompl(Clk);	
158	
159			-- No IRQ on Ringbuf Wrap
160			print(">> No IRQ on Ringbuf Wrap");
161			InitTestCase(Clk, Rst);
162			TestCase := 5;
163			ConfigureAuto(	WinSize => 4096*2, Ringbuf => '1', Overwrite => '1', Wincnt => 2, Wincur => 0);	
164			Inp_Level(0) <= LvlThreshold_c;		
165			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
166			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
167			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
168			Inp_Level(0) <= (others => '0');
169			ControlWaitCompl(Clk);		
