173		procedure dma_cmd (
174			signal Clk : in std_logic;
175			signal StrIrq : in std_logic_vector;
176			signal Dma_Cmd : in DaqSm2DaqDma_Cmd_t;
177			signal Dma_Cmd_Vld : in std_logic;
178			constant Generics_c : Generics_t) is
179		begin
180			-- Normal Order
181			WaitForCase(0,  Clk);
182			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, ExeSize=> 512, Msg => "Wr0.0",
183								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);
184			ProcDone(2)	:= '1';			
185			
186			-- Flipped Order
187			WaitForCase(1,  Clk);
188			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, ExeSize=> 512, Msg => "Wr0.0",
189								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);
190			ProcDone(2)	:= '1';			
191			
192			-- IRQ FIFO full
193			WaitForCase(2,  Clk);
194			-- Fill FIFO
195			for i in 0 to 11 loop
196				ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, ExeSize=> 512, Msg => "Wr" & to_string(i), NextWin => true,
197									Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);
198			end loop;
199			-- Checked transfer
200			CheckNoActivity(Dma_Cmd_Vld, 1 us, 0, "Full");
201			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, ExeSize=> 512, Msg => "Wr12", NextWin => true,
202								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);
203			ProcDone(2)	:= '1';	
204			
205			-- Multi-Stream
206			WaitForCase(3,  Clk);
207			for i in 3 downto 0 loop
208				ExpectDmaCmdAuto(	Stream	=> i, MaxSize => 4096, ExeSize=> 512*(i+1), Msg => "Wr" & to_string(i), NextWin => true,
209									Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);		
210			end loop;
211			ProcDone(2)	:= '1';	
212			
213			-- Win-Change without trigger
214			WaitForCase(4,  Clk);
215			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, Msg => "Wr0",
216								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);	
217			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, Msg => "Wr0", NextWin => true,
218								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);	
219			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, Msg => "Wr0",
220								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);								
221			ProcDone(2)	:= '1';	
222			
223			-- No IRQ on Ringbuf Wrap
224			WaitForCase(5,  Clk);
225			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, Msg => "Wr0",
226								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);	
227			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, Msg => "Wr0", 
228								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);	
229			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, Msg => "Wr0",
230								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);								
231			ProcDone(2)	:= '1';			
232			
233		end procedure;
