235		procedure dma_resp (
236			signal Clk : in std_logic;
237			signal StrIrq : in std_logic_vector;
238			signal Dma_Resp : inout DaqDma2DaqSm_Resp_t;
239			signal Dma_Resp_Vld : inout std_logic;
240			signal Dma_Resp_Rdy : in std_logic;
241			signal TfDone : inout std_logic;
242			signal StrLastWin : in WinType_a(Streams_g-1 downto 0);
243			constant Generics_c : Generics_t) is
244		begin
245			-- Normal Order
246			WaitForCase(0,  Clk);
247			ApplyDmaRespAuto(	Stream => 0, Trigger => '1',
248								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);	
249			wait for 200 ns;
250			StdlvCompareStdlv ("0000", StrIrq, "IRQs asserted unexpectedly");
251			assert StrIrq'last_event > 200 ns report "###ERROR###: IRQs not idle" severity error;
252			AssertTfDone(Clk, TfDone);
253			CheckIrq(MaxWait => (1 us), Stream => 0, LastWin => 0, Clk => Clk, StrIrq => StrIrq, StrLastWin => StrLastWin);	
254			ProcDone(1)	:= '1';	
255			
256			-- Flipped Order
257			WaitForCase(1,  Clk);
258			AssertTfDone(Clk, TfDone);
259			wait for 200 ns;
260			StdlvCompareStdlv ("0000", StrIrq, "IRQs asserted unexpectedly");
261			assert StrIrq'last_event > 200 ns report "###ERROR###: IRQs not idle" severity error;
262			ApplyDmaRespAuto(	Stream => 0, Trigger => '1',
263								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);		
264			CheckIrq(MaxWait => (1 us), Stream => 0, LastWin => 0, Clk => Clk, StrIrq => StrIrq, StrLastWin => StrLastWin);		
265			ProcDone(1)	:= '1';			
266			
267			-- IRQ FIFO full
268			WaitForCase(2,  Clk);
269			-- Fill FIFO
270			for i in 0 to 11 loop
271				ApplyDmaRespAuto(	Stream => 0, Trigger => '1',
272									Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);	
273			end loop;
274			-- Wait
275			wait for 1.1 us;
276			-- Send IRQs
277			for i in 0 to 11 loop
278				AssertTfDone(Clk, TfDone);
279				CheckIrq(MaxWait => (1 us), Stream => 0, LastWin => i mod 3, Clk => Clk, StrIrq => StrIrq, StrLastWin => StrLastWin);		
280			end loop;
281			-- Last transfer
282			ApplyDmaRespAuto(	Stream => 0, Trigger => '1',
283								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);	
284			AssertTfDone(Clk, TfDone);
285			CheckIrq(MaxWait => (1 us), Stream => 0, LastWin => 0, Clk => Clk, StrIrq => StrIrq, StrLastWin => StrLastWin);			
286			ProcDone(1)	:= '1';	
287			
288			-- Multi-Stream
289			WaitForCase(3,  Clk);
290			for i in 3 downto 0 loop
291				ApplyDmaRespAuto(	Stream => i, Trigger => '1',
292									Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);	
293			end loop;
294			for i in 3 downto 0 loop
295				AssertTfDone(Clk, TfDone);
296				CheckIrq(MaxWait => (1 us), Stream => i, LastWin => 0, Clk => Clk, StrIrq => StrIrq, StrLastWin => StrLastWin);	
297			end loop;		
298			ProcDone(1)	:= '1';	
299			
300			-- Win-Change without trigger
301			WaitForCase(4,  Clk);
302			wait for 100 ns;
303			ApplyDmaRespAuto(	Stream => 0, Trigger => '0',
304								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);		
305			AssertTfDone(Clk, TfDone);
306			CheckNoActivityStlv(StrIrq, 100 ns, 0, "Before Window Change");
307			wait for 100 ns;
308			ApplyDmaRespAuto(	Stream => 0, Trigger => '0',
309								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);	
310			AssertTfDone(Clk, TfDone);
311			CheckIrq(MaxWait => (1 us), Stream => 0, LastWin => 0, Clk => Clk, StrIrq => StrIrq, StrLastWin => StrLastWin);		
312			wait for 100 ns;
313			ApplyDmaRespAuto(	Stream => 0, Trigger => '0',
314								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);
315			AssertTfDone(Clk, TfDone);
316			CheckNoActivityStlv(StrIrq, 100 ns, 0, "After Window Change");
317			ProcDone(1)	:= '1';	
318			
319			-- No IRQ on Ringbuf Wrap
320			WaitForCase(5,  Clk);
321			wait for 100 ns;
322			ApplyDmaRespAuto(	Stream => 0, Trigger => '0',
323								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);		
324			AssertTfDone(Clk, TfDone);
325			CheckNoActivityStlv(StrIrq, 100 ns, 0, "Before Wrap");
326			wait for 100 ns;
327			ApplyDmaRespAuto(	Stream => 0, Trigger => '0',
328								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);	
329			AssertTfDone(Clk, TfDone);
330			CheckNoActivityStlv(StrIrq, 100 ns, 0, "Wrap");
331			wait for 100 ns;
332			ApplyDmaRespAuto(	Stream => 0, Trigger => '0',
333								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);
334			AssertTfDone(Clk, TfDone);
335			CheckNoActivityStlv(StrIrq, 100 ns, 0, "After Wrap");
336			ProcDone(1)	:= '1';			
337			
338		end procedure;
339		
