366			ExpCtxFullBurstAuto(	Stream => 0, NextWin => true, IsTrig => true,
367									Clk => Clk, CtxStr_Cmd => CtxStr_Cmd, CtxStr_Resp => CtxStr_Resp, CtxWin_Cmd => CtxWin_Cmd, CtxWin_Resp => CtxWin_Resp);
368			ProcDone(0)	:= '1';
