380			ExpCtxFullBurstAuto(	Stream => 0, Msg => "Wr0.0", 
381									Clk => Clk, CtxStr_Cmd => CtxStr_Cmd, CtxStr_Resp => CtxStr_Resp, CtxWin_Cmd => CtxWin_Cmd, CtxWin_Resp => CtxWin_Resp);
