389			WaitForCase(5, Clk);
390			ExpCtxFullBurstAuto(	Stream => 0, Msg => "Wr0.0", 
391									Clk => Clk, CtxStr_Cmd => CtxStr_Cmd, CtxStr_Resp => CtxStr_Resp, CtxWin_Cmd => CtxWin_Cmd, CtxWin_Resp => CtxWin_Resp);
392			ExpCtxFullBurstAuto(	Stream => 0, Msg => "Wr0.1", 
393									Clk => Clk, CtxStr_Cmd => CtxStr_Cmd, CtxStr_Resp => CtxStr_Resp, CtxWin_Cmd => CtxWin_Cmd, CtxWin_Resp => CtxWin_Resp);
394			ExpCtxFullBurstAuto(	Stream => 0, Msg => "Wr0.2",
395									Clk => Clk, CtxStr_Cmd => CtxStr_Cmd, CtxStr_Resp => CtxStr_Resp, CtxWin_Cmd => CtxWin_Cmd, CtxWin_Resp => CtxWin_Resp);								
396			ProcDone(0)	:= '1';			
397			
398		end procedure;
399		
400	end;
